from pathlib import Path
import ast
for fname in ['model.py','predict.py']:
    p=Path(fname)
    print(f'===== {fname} exists={p.exists()} size={p.stat().st_size if p.exists() else None} =====')
    if not p.exists():
        continue
    txt=p.read_text(errors='replace')
    try:
        tree=ast.parse(txt)
        for node in tree.body:
            if isinstance(node,(ast.Import,ast.ImportFrom)):
                continue
            if isinstance(node, ast.ClassDef):
                print(f'CLASS {node.name} lines {node.lineno}-{node.end_lineno}')
                for sub in node.body:
                    if isinstance(sub, ast.FunctionDef):
                        print(f'  METHOD {sub.name} lines {sub.lineno}-{sub.end_lineno}')
            elif isinstance(node, ast.FunctionDef):
                print(f'FUNC {node.name} lines {node.lineno}-{node.end_lineno}')
    except Exception as e:
        print('ASTERR',repr(e))
    lines=txt.splitlines()
    wanted=[]
    for i,l in enumerate(lines, start=1):
        low=l.lower()
        if any(term in low for term in ['class pi0', 'def reset', 'def predict', 'predict_action_chunk', 'select_action', 'def main', 'evaluator', 'evaluate_single_episode', 'control_mode', 'def load']):
            wanted.append(i)
    ranges=[]
    for i in wanted:
        a=max(1,i-8); b=min(len(lines),i+45)
        if not ranges or a>ranges[-1][1]+1:
            ranges.append([a,b])
        else:
            ranges[-1][1]=max(ranges[-1][1],b)
    for a,b in ranges[:6]:
        print(f'--- {fname}:{a}-{b} ---')
        for j in range(a,b+1):
            print(f'{j:04d}: {lines[j-1][:180]}')
